dslRule:
/*!id: jdt.internal.recoveredtypebinding.getcompilationunit.to.gettype*/
/*!description: Refines internal JDT RecoveredTypeBinding logic by getting the specific IType from the ICompilationUnit.*/
/*!severity: info*/
((org.eclipse.jdt.internal.core.PackageFragment) $javaElement).getCompilationUnit(getInternalName() + org.eclipse.jdt.internal.compiler.codegen.ConstantPool.SUFFIX_STRING_java)
:: inClass("org.eclipse.jdt.core.dom.RecoveredTypeBinding")
=> ((org.eclipse.jdt.internal.core.PackageFragment) $javaElement).getCompilationUnit(getInternalName() + org.eclipse.jdt.internal.compiler.codegen.ConstantPool.SUFFIX_STRING_java).getType(getName())
;;

/*!id: jdt.internal.typebinding.getcompilationunit.to.gettype*/
/*!description: Refines internal JDT TypeBinding logic by getting the specific IType from the ICompilationUnit.*/
/*!severity: info*/
((org.eclipse.jdt.internal.core.PackageFragment) $javaElement).getCompilationUnit(new java.lang.String(this.binding.sourceName()) + org.eclipse.jdt.internal.compiler.codegen.ConstantPool.SUFFIX_STRING_java)
:: inClass("org.eclipse.jdt.core.dom.TypeBinding")
=> ((org.eclipse.jdt.internal.core.PackageFragment) $javaElement).getCompilationUnit(new java.lang.String(this.binding.sourceName()) + org.eclipse.jdt.internal.compiler.codegen.ConstantPool.SUFFIX_STRING_java).getType(getName())
;;
